INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2bfb262c-62bd-4d67-8242-dd1a919b2a6f',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL — OLTP, OLAP, and Four Paradigms in One Database$escape$,
  $escape$PostgreSQL's hybrid nature makes it tempting to use for everything—but workload type still matters. For OLTP, its row-store, MVCC, and strict ACID semantics shine: high-concurrency writes with predictable sub-millisecond latency. For OLAP at scale, it struggles without extensions—Citus adds columnar storage via `CREATE TABLE ... USING columnar`, and `pg_partman` manages time-series partitioning to prune scan ranges with BRIN indexes.

PostgreSQL natively spans three paradigms: relational (default heap tables), document (JSONB + GIN indexes with `jsonb_path_ops`), and full-text search (`tsvector`/`tsquery` + `pg_trgm` for trigram similarity). Wide-column is the weak spot—no native sparse columns, and simulating it with JSONB adds write amplification on updates.

Audit access patterns before adding a specialist store: point lookups + transactions → normalized relational tables with B-tree indexes; semi-structured event data → JSONB with `@>` containment queries; keyword search → `tsvector` with `plainto_tsquery`; analytics at scale → Citus columnar or an external OLAP. PostgreSQL's extensibility delays polyglot pressure, but not indefinitely.$escape$,
  $escape$-- OLTP: ACID-safe balance transfer
BEGIN;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;

-- Document: JSONB containment with GIN index
CREATE INDEX idx_events_gin ON events USING GIN (data jsonb_path_ops);
SELECT id FROM events WHERE data @> '{"type": "click", "source": "mobile"}';

-- Full-text search
SELECT id, title FROM articles
WHERE to_tsvector('english', title || ' ' || body) @@ plainto_tsquery('postgresql indexing');

-- OLAP: columnar storage via Citus extension
CREATE TABLE metrics (ts TIMESTAMPTZ, value FLOAT) USING columnar;$escape$,
