INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '87e8b1a3-eed0-4a24-8758-4bd0f2263fc7',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL — GIN Indexes on JSONB: End the Seq Scans$escape$,
  $escape$JSONB columns without a GIN index force PostgreSQL to deserialize and scan every row — a Seq Scan that kills performance at scale. A standard GIN index covers all keys and values, enabling the @>, ?, ?|, and ?& operators to run as index lookups instead.

For narrower, read-heavy access patterns, jsonb_path_ops cuts index size significantly by only covering containment paths. The tradeoff: key-existence checks (? operator) no longer use the index.

Always verify with EXPLAIN (ANALYZE, BUFFERS). A Bitmap Heap Scan via the GIN index is the happy path. If you're still hitting a Seq Scan, check whether your WHERE clause predicate is actually covered by the chosen operator class.

GIN indexes carry higher write amplification than B-tree. On insert-heavy workloads, fastupdate=on batches pending entries in a side list — tune gin_pending_list_limit (default 4MB) to control when that list flushes. Setting fastupdate=off gives consistent write latency at the cost of slower individual inserts.$escape$,
  $escape$-- Default GIN: covers all operators (@>, ?, ?|, ?&)
CREATE INDEX idx_events_metadata ON events USING GIN (metadata);

-- jsonb_path_ops: smaller index, containment-only (@> only)
CREATE INDEX idx_events_metadata_path ON events USING GIN (metadata jsonb_path_ops);

-- Verify index usage (look for "Bitmap Index Scan on idx_events_metadata")
EXPLAIN (ANALYZE, BUFFERS)
SELECT * FROM events
WHERE metadata @> '{"status": "active", "region": "eu-west"}';

-- Write-heavy workloads: disable fastupdate for consistent insert latency
CREATE INDEX idx_events_metadata_nowait ON events
  USING GIN (metadata) WITH (fastupdate = off);$escape$,
