INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '95a90493-5ee1-4ccb-9f2d-6af7d2d4cb9e',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL + TimescaleDB — Hypertables, Continuous Aggregates, and Compression in Practice$escape$,
  $escape$TimescaleDB extends PostgreSQL with time-series primitives that slot directly into your existing psql workflow. A hypertable is a standard PostgreSQL table partitioned automatically by time — create it with `SELECT create_hypertable('metrics', 'recorded_at')` after your normal `CREATE TABLE`. Queries use identical SQL; TimescaleDB's planner prunes irrelevant chunks automatically.

Continuous aggregates replace expensive recurring rollup jobs. Define a materialized view with `CREATE MATERIALIZED VIEW hourly_avg WITH (timescaledb.continuous) AS SELECT time_bucket('1 hour', recorded_at) AS bucket, avg(value) FROM metrics GROUP BY bucket`. Refresh policy handles incremental updates — no full recompute.

Native compression is column-oriented: `ALTER TABLE metrics SET (timescaledb.compress, timescaledb.compress_orderby = 'recorded_at DESC'); SELECT add_compression_policy('metrics', INTERVAL '7 days')`. Older chunks compress automatically, often achieving 90%+ size reduction while remaining queryable via transparent decompression. All of this runs inside your existing PostgreSQL connection — no separate daemon, no new driver.$escape$,
  $escape$-- 1. Create hypertable
CREATE TABLE metrics (recorded_at TIMESTAMPTZ NOT NULL, sensor_id INT, value DOUBLE PRECISION);
SELECT create_hypertable('metrics', 'recorded_at');

-- 2. Continuous aggregate
CREATE MATERIALIZED VIEW hourly_avg
WITH (timescaledb.continuous) AS
SELECT time_bucket('1 hour', recorded_at) AS bucket,
       sensor_id, avg(value) AS avg_value
FROM metrics
GROUP BY bucket, sensor_id;
SELECT add_continuous_aggregate_policy('hourly_avg', '2 hours', '1 hour', '1 hour');

-- 3. Enable compression on chunks older than 7 days
ALTER TABLE metrics SET (timescaledb.compress, timescaledb.compress_orderby = 'recorded_at DESC');
SELECT add_compression_policy('metrics', INTERVAL '7 days');$escape$,
