INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ce5c33f3-c443-439c-a2eb-a26086eba7b4',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL Indexing Strategy — B-tree, Hash, GIN, BRIN, Covering, and Partial Indexes$escape$,
  $escape$PostgreSQL defaults to B-tree for a reason: it handles equality, range, ORDER BY, and IS NULL efficiently on most scalar types. Hash indexes are faster for pure equality lookups (=) but useless for ranges and can't be WAL-logged before PG10 — prefer them only on high-cardinality UUID or hash-keyed columns. GIN shines on composite values: use it for jsonb @>, array &&, and tsvector @@ queries. BRIN is the secret weapon for append-only, physically ordered tables (logs, time-series) — a BRIN on created_at across 100M rows costs kilobytes of storage versus a B-tree's gigabytes, at the cost of less precision. Covering indexes (INCLUDE) let you satisfy queries entirely from the index without a heap fetch — critical for hot read paths. Partial indexes slash index size and maintenance cost when your WHERE clause carves out a selective subset. Stack them: a partial GIN on a jsonb column filtered to active rows only is a valid production pattern in PostgreSQL.$escape$,
  $escape$-- Covering index: avoid heap fetch on hot user lookup
CREATE INDEX idx_users_email_covering
  ON users (email)
  INCLUDE (id, display_name);

-- Partial index: only index unprocessed jobs (selective subset)
CREATE INDEX idx_jobs_pending
  ON jobs (created_at)
  WHERE status = 'pending';

-- GIN index for JSONB containment queries
CREATE INDEX idx_events_payload_gin
  ON events USING gin (payload jsonb_path_ops);

-- BRIN for append-only time-series (low storage cost)
CREATE INDEX idx_logs_ts_brin
  ON logs USING brin (logged_at) WITH (pages_per_range = 128);

-- Verify index usage
EXPLAIN (ANALYZE, BUFFERS)
SELECT id, display_name FROM users WHERE email = 'sravan@example.com';$escape$,
  $escape$sql$escape$,
