INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5ce13d2b-c4ac-4ba7-a293-1d661a41b092',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL Query Optimization — EXPLAIN ANALYZE, Slow Query Log, and Killing N+1$escape$,
  $escape$EXPLAIN ANALYZE is your ground truth in PostgreSQL — unlike EXPLAIN alone, it executes the query and surfaces actual row counts and timing per plan node. Run it as `EXPLAIN (ANALYZE, BUFFERS, FORMAT TEXT)` to expose I/O alongside timing. Watch for nodes where `actual rows` vastly exceeds `rows` estimate: this is the planner operating on stale statistics. Fix it with `ANALYZE <table>` or tune `autovacuum_analyze_scale_factor` for high-churn tables.

A `Seq Scan` on a large table with low-selectivity filters almost always means a missing index. A `Nested Loop` with escalating loop counts is the mechanical fingerprint of N+1 — dozens of identical parameterized queries hitting the same table. Collapse them with `= ANY($1::int[])`, a lateral join, or a CTE.

For fleet-wide visibility, pair `pg_stat_statements` with the slow query log (`log_min_duration_statement`). Sort by `mean_exec_time` to find chronic offenders. When debugging planner choices, toggle join strategies with `SET enable_hashjoin = off` locally — but revert before committing. The planner's cost model is tunable via `seq_page_cost` and `random_page_cost`; dropping `random_page_cost` to 1.1 on SSD-backed instances often unlocks better index usage.$escape$,
  $escape$-- Enable fleet-wide query telemetry
CREATE EXTENSION IF NOT EXISTS pg_stat_statements;

-- Surface the worst offenders by mean latency
SELECT
  left(query, 80)        AS query_preview,
  calls,
  round(mean_exec_time::numeric, 2) AS mean_ms,
  round(total_exec_time::numeric, 2) AS total_ms
FROM pg_stat_statements
ORDER BY mean_exec_time DESC
LIMIT 10;

-- Deep-dive: actual vs. estimated rows + buffer hits
EXPLAIN (ANALYZE, BUFFERS, FORMAT TEXT)
SELECT u.id, COUNT(p.id)
FROM users u
JOIN posts p ON p.user_id = u.id
WHERE u.created_at > NOW() - INTERVAL '30 days'
GROUP BY u.id;$escape$,
