INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '46671bb2-d87b-4ea7-9034-1ad426b5df5f',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL Data Modeling — Normalization vs. Denormalization for Real Access Patterns$escape$,
  $escape$Normalized schemas protect integrity via FK constraints and reduce write amplification — the right default when writes dominate. Denormalization trades storage for read throughput, and PostgreSQL gives you surgical tools for this tradeoff without abandoning relational guarantees.

For read-heavy access patterns, `MATERIALIZED VIEW` with `REFRESH MATERIALIZED VIEW CONCURRENTLY` pre-computes expensive joins without blocking live reads. For sparse or semi-structured attributes, a `JSONB` column with a `GIN` index (`jsonb_path_ops`) avoids wide nullable tables while keeping query flexibility via `@>` and `#>>` operators.

Use `GENERATED ALWAYS AS (expr) STORED` for derived columns that stay consistent automatically — no application-side sync needed. When queries filter on a predictable subset, partial indexes (`WHERE status = 'active'`) compress index size and sharpen planner selectivity.

Diagnose your real access patterns with `pg_stat_user_tables`: high `seq_scan` counts on large tables signal under-indexing or over-normalization. Covering indexes (`INCLUDE (col)`) eliminate heap fetches on hot read paths — effectively giving you denormalization benefits inside an otherwise normalized schema.$escape$,
  $escape$-- Normalized base
CREATE TABLE articles (
  id        BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  author_id BIGINT REFERENCES authors(id),
  title     TEXT NOT NULL,
  metadata  JSONB DEFAULT '{}'
);
CREATE INDEX ON articles USING GIN (metadata jsonb_path_ops);

-- Denormalized read layer
CREATE MATERIALIZED VIEW article_feed AS
SELECT a.id, a.title, au.display_name AS author_name,
       a.metadata ->> 'primary_tag' AS tag
FROM   articles a
JOIN   authors au ON au.id = a.author_id;

REFRESH MATERIALIZED VIEW CONCURRENTLY article_feed;$escape$,
  $escape$sql$escape$,
