INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ade167ec-c5d2-4b6b-bc24-8afecb5a05f5',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL Transactions — Isolation Levels and Optimistic vs Pessimistic Locking$escape$,
  $escape$PostgreSQL's default isolation level is READ COMMITTED — each statement gets a fresh snapshot, so two statements within the same transaction can observe different data if a concurrent commit lands between them. For consistent reads across statements, upgrade to REPEATABLE READ or SERIALIZABLE.

PostgreSQL uses MVCC under the hood: reads never block writes, but write-write conflicts still cause waits or errors.

Pessimistic locking with SELECT ... FOR UPDATE acquires row-level locks immediately, blocking concurrent writers until your transaction commits. Add SKIP LOCKED for queue-style workloads — it skips already-locked rows instead of waiting, enabling parallel consumers.

Optimistic locking avoids database locks entirely. Add a version INTEGER column, increment it on every write, and check it in the WHERE clause. If UPDATE returns 0 rows affected, a concurrent transaction won the race — retry at the application layer.

SERIALIZABLE in PostgreSQL uses Serializable Snapshot Isolation (SSI): it detects read-write dependency cycles at commit time and raises ERROR 40001 (serialization failure) rather than silently returning stale data. Safest option, but mandates explicit retry logic. For high-contention rows like counters or seat reservations, pessimistic locking under REPEATABLE READ usually outperforms optimistic strategies by eliminating retry stampedes.$escape$,
  $escape$-- Pessimistic: lock row for the full transaction
BEGIN;
SELECT balance FROM accounts WHERE id = $1 FOR UPDATE;
UPDATE accounts SET balance = balance - 100 WHERE id = $1;
COMMIT;

-- Optimistic: detect conflict via version column
BEGIN;
SELECT balance, version FROM accounts WHERE id = $1;
-- application reads version = 7, then:
UPDATE accounts
  SET balance = balance - 100, version = version + 1
  WHERE id = $1 AND version = 7;  -- 0 rows = lost update, retry
COMMIT;

-- Queue consumer: skip rows locked by other workers
SELECT * FROM jobs WHERE status = 'pending'
ORDER BY created_at FOR UPDATE SKIP LOCKED LIMIT 1;$escape$,
