INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'af80f506-935f-4d6c-b3b4-7b44941f78e1',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL Sharding — Shard Key Selection and Avoiding Hot Spots with Citus$escape$,
  $escape$PostgreSQL alone doesn't shard — you need the `citus` extension to distribute tables across worker nodes. The shard key is the most consequential decision: it determines how rows are hashed across shards and which queries get pruned to a single node vs. broadcast to all.

`create_distributed_table('orders', 'user_id')` hashes `user_id` across 32 shards by default. This works because `user_id` has high cardinality and almost every query filters on it — Citus prunes to a single shard without touching others. Never use `created_at` or a serial `id` as the shard key: sequential values cluster in early shards during initial load, and range queries scatter across all nodes, turning into expensive broadcast queries.

Hot spots appear when a few shard key values carry disproportionate write volume — a single power-user account generating 80% of inserts, for example. Diagnose with `citus_stat_statements` grouped by `shardid`. Structural skew requires a composite key like `(tenant_id, user_id)` to redistribute load; incidental skew can be fixed with `rebalance_table_shards()`.

Always colocate related tables on the same shard key so JOINs stay node-local and don't require cross-node data shuffles.$escape$,
  $escape$-- Enable Citus extension
CREATE EXTENSION IF NOT EXISTS citus;

-- Distribute on high-cardinality key; Citus hashes across 32 shards
SELECT create_distributed_table('orders', 'user_id');

-- Colocate order_items so JOIN with orders stays node-local
SELECT create_distributed_table('order_items', 'user_id', colocate_with => 'orders');

-- Detect hot shards: high call count on a single shardid = hot spot
SELECT shardid, sum(calls) AS total_calls
FROM citus_stat_statements
GROUP BY shardid
ORDER BY total_calls DESC
LIMIT 5;

-- Rebalance shards across workers when load skews
SELECT rebalance_table_shards('orders');$escape$,
