INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a4fa8408-b14f-46c0-aae6-fdc17de5d8f3',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL PITR — Backup Strategies That Actually Hit Your RTO and RPO$escape$,
  $escape$PostgreSQL's Point-in-Time Recovery relies on a base backup plus a continuous WAL (Write-Ahead Log) archive. Your RPO is directly tied to your WAL archiving frequency — `archive_command` ships WAL segments, so a 5-minute segment flush means up to 5 minutes of data loss on failure. Use `archive_status` and monitor `pg_stat_archiver.last_failed_time` to catch silent archive failures before they wreck your recovery window.

For RTO, the bottleneck isn't restoring the base backup — it's WAL replay. A 100GB database with 12 hours of WAL can take 30–90 minutes to replay. Use `pg_basebackup` with `-Ft -z` for compressed tar-format base backups, and set `recovery_target_time` in `postgresql.conf` to stop replay at a precise timestamp. Combine with `restore_command` pointing to your WAL archive (S3, Azure Blob, or `pgBackRest`). `pgBackRest` is the production standard: it supports parallel WAL fetch, delta restores, and retention policies out of the box — critical when base backups exceed 500GB.$escape$,
  $escape$# postgresql.conf — WAL archiving setup
archive_mode = on
archive_command = 'pgbackrest --stanza=main archive-push %p'
wal_level = replica

# recovery.conf (or postgresql.conf in PG12+)
restore_command = 'pgbackrest --stanza=main archive-get %f "%p"'
recovery_target_time = '2026-04-15 14:30:00+00'
recovery_target_action = 'promote'

-- Check archive health
SELECT last_archived_wal, last_failed_wal, last_failed_time
FROM pg_stat_archiver;$escape$,
  $escape$bash$escape$,
