INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '20903e03-f5dc-40ff-a2af-960bebd9bbea',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL Security — RLS, Least Privilege, and Encryption You Actually Need to Configure$escape$,
  $escape$PostgreSQL doesn't encrypt at rest by default — that's delegated to the filesystem (e.g., LUKS on Linux or Azure Disk Encryption). What you control directly is transit encryption and access scoping. Force TLS by setting `ssl = on` in `postgresql.conf` and `hostssl all all 0.0.0.0/0 scram-sha-256` in `pg_hba.conf` — reject plain `host` entries entirely. For row-level security, enable it per table with `ALTER TABLE ... ENABLE ROW LEVEL SECURITY`, then create policies using `USING` (read filter) and `WITH CHECK` (write filter) clauses tied to `current_user` or a session variable like `app.current_tenant_id`. Never run application queries as a superuser. Create a dedicated role with only `SELECT`, `INSERT`, `UPDATE` on required tables — no `DELETE`, no schema ownership. Use `SET ROLE` at session start if you need privilege escalation scoped to a transaction. Column-level encryption for PII fields can be layered with `pgcrypto`'s `pgp_sym_encrypt` before writes — decryption happens in the query, not the application layer.$escape$,
  $escape$-- Enable RLS and create a tenant-scoped policy
ALTER TABLE user_data ENABLE ROW LEVEL SECURITY;
ALTER TABLE user_data FORCE ROW LEVEL SECURITY;

CREATE POLICY tenant_isolation ON user_data
  USING (tenant_id = current_setting('app.current_tenant_id')::uuid)
  WITH CHECK (tenant_id = current_setting('app.current_tenant_id')::uuid);

-- Least-privilege app role
CREATE ROLE app_user NOLOGIN;
GRANT SELECT, INSERT, UPDATE ON user_data TO app_user;
REVOKE DELETE ON user_data FROM app_user;

-- Encrypt PII column at write time
INSERT INTO user_data (tenant_id, email_enc)
VALUES (
  current_setting('app.current_tenant_id')::uuid,
  pgp_sym_encrypt('user@example.com', current_setting('app.encryption_key'))
);$escape$,
