INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4d9819ce-7397-47bd-adc9-ed0664536f8c',
  '00000000-0000-0000-0000-000000000001',
  $escape$PostgreSQL Zero-Downtime Migrations — NOT VALID, Backfill, Then Enforce$escape$,
  $escape$Adding a NOT NULL column to a large PostgreSQL table the naive way — `ALTER TABLE ADD COLUMN col TEXT NOT NULL DEFAULT 'x'` — acquires an `AccessExclusiveLock` and rewrites the table on PostgreSQL < 11. Even on PG 11+, where constant defaults are stored in catalog metadata instead of rewriting, the NOT NULL check still scans every row under a lock.

The safe pattern splits the migration into three independent transactions: first add the column as nullable (near-instant, no lock contention), then backfill existing rows in bounded batches using `UPDATE ... WHERE id BETWEEN $1 AND $2` to avoid long-running transactions bloating `pg_wal`, and finally enforce the constraint with `ADD CONSTRAINT col_not_null CHECK (col IS NOT NULL) NOT VALID` followed separately by `VALIDATE CONSTRAINT col_not_null`.

`NOT VALID` skips scanning existing rows entirely — zero lock. `VALIDATE CONSTRAINT` runs under `ShareUpdateExclusiveLock`, which blocks DDL but allows concurrent reads and writes. This is the only PostgreSQL-native path to constraint enforcement without a table freeze. Tools like `pgroll` automate this three-phase pattern and manage dual-schema views for backward compatibility during rollouts.$escape$,
  $escape$-- Phase 1: add nullable (no rewrite, no lock)
ALTER TABLE events ADD COLUMN source TEXT;

-- Phase 2: backfill in batches (adjust range to your table size)
UPDATE events SET source = 'legacy' WHERE id BETWEEN 1 AND 100000 AND source IS NULL;
-- repeat until complete

-- Phase 3a: add constraint without scanning existing rows
ALTER TABLE events
  ADD CONSTRAINT events_source_not_null CHECK (source IS NOT NULL) NOT VALID;

-- Phase 3b: validate under ShareUpdateExclusiveLock (reads/writes still allowed)
ALTER TABLE events VALIDATE CONSTRAINT events_source_not_null;$escape$,
  $escape$sql$escape$,
