INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0dc3ebb6-d067-44c6-b5b6-4bf4836457af',
  '00000000-0000-0000-0000-000000000001',
  $escape$postgresql_de Monitoring — Slow Queries, Connections, Replication Lag & Storage in One View$escape$,
  $escape$PostgreSQL exposes everything you need through its system catalog views — no external agent required for baseline observability. For slow queries, `pg_stat_statements` is your first stop: sort by `total_exec_time / calls` to surface high-average-latency queries, or by `total_exec_time` to find cumulative cost leaders. Reset it with `pg_stat_statements_reset()` after schema changes to avoid stale baselines. Connection pressure lives in `pg_stat_activity` — group by `state` to distinguish active, idle, and idle-in-transaction sessions. Idle-in-transaction connections are particularly dangerous; they hold locks and block autovacuum. Replication lag is exposed via `pg_stat_replication`: the `write_lag`, `flush_lag`, and `replay_lag` interval columns give you per-standby pipeline depth. A non-null `sent_lsn - replay_lsn` delta quantifies byte lag precisely. For storage growth, `pg_database_size(current_database())` gives total DB size, while `pg_total_relation_size(relid)` from `pg_stat_user_tables` ranks bloated tables including their TOAST and indexes. Combine these into a single monitoring query and schedule it via `pg_cron` or scrape it with a Prometheus `postgres_exporter` custom collector.$escape$,
  $escape$-- PostgreSQL unified monitoring snapshot
SELECT 'slow_queries' AS metric,
       query,
       round((total_exec_time / calls)::numeric, 2) AS avg_ms,
       calls
FROM pg_stat_statements
ORDER BY avg_ms DESC
LIMIT 5

UNION ALL

SELECT 'idle_in_txn_connections',
       usename || '@' || datname,
       EXTRACT(EPOCH FROM (now() - state_change))::numeric,
       NULL
FROM pg_stat_activity
WHERE state = 'idle in transaction'

UNION ALL

SELECT 'replication_lag_bytes',
       application_name,
       (sent_lsn - replay_lsn)::numeric,
       NULL
FROM pg_stat_replication;$escape$,
